RuleSet.GenFile:
#!/bin/bash # # @(#) $GenPackageDir$/$GenFileName$ $MssBashScriptLicense$ $parseMySqlArgs$$validateMySqlArgs$ echo "Dropping any existing schema $DbSchemaName$ for $$mysqluser" echo "Dropping any existing schema $DbSchemaName$ for $$mysqluser" >>$$logfilename mysql -v -u $$mysqluser --password=$$mysqlpwd --execute="drop schema $lower DbSchemaName$" >>$$logfilename 2>&1
echo "Creating schema $DbSchemaName$ for $$mysqluser" echo "Creating schema $DbSchemaName$ $$mysqluser" >>$$logfilename mysql -v -u $$mysqluser --password=$$mysqlpwd --execute="create schema $lower DbSchemaName$" >>$$logfilename 2>&1
$exec_CreateAllTables$$exec_CreateAllIndexes$$exec_CreateAllRelations$$exec_CreateAllStoredProcs$$exec_LoadAllData$$exec_CreateAllTriggers$ exit 0
